#define SIZE 64
void ring_buffer(int data_in, int *data_out, int write, int read, int buf[SIZE]) {
    #pragma HLS PIPELINE OFF
    static int wr_ptr = 0, rd_ptr = 0;
    if (write) {
        buf[wr_ptr] = data_in;
        wr_ptr = (wr_ptr + 1) % SIZE;
    }
    if (read) {
        *data_out = buf[rd_ptr];
        rd_ptr = (rd_ptr + 1) % SIZE;
    }
}

#define N 256
void leaky_relu(int input[N], int output[N], int alpha) {
    #pragma HLS PIPELINE OFF
    for (int i = 0; i < N; i++) {
        #pragma HLS UNROLL factor=1
        output[i] = (input[i] > 0) ? input[i] : (input[i] * alpha) >> 8;
    }
}

#define N 128
void hamming_dist(int a[N], int b[N], int *distance) {
    #pragma HLS PIPELINE OFF
    int dist = 0;
    for (int i = 0; i < N; i++) {
        #pragma HLS UNROLL factor=1
        dist += (a[i] != b[i]) ? 1 : 0;
    }
    *distance = dist;
}

#define H 32
#define W 32
void rgb2gray(int r[H][W], int g[H][W], int b[H][W], int gray[H][W]) {
    #pragma HLS PIPELINE OFF
    for (int i = 0; i < H; i++)
        for (int j = 0; j < W; j++) {
            #pragma HLS UNROLL factor=1
            gray[i][j] = (r[i][j] * 77 + g[i][j] * 150 + b[i][j] * 29) >> 8;
        }
}

#define N 64
void popcount(unsigned int data[N], int counts[N]) {
    #pragma HLS PIPELINE OFF
    for (int i = 0; i < N; i++) {
        #pragma HLS UNROLL factor=1
        int c = 0;
        unsigned int x = data[i];
        for (int b = 0; b < 32; b++)
            c += (x >> b) & 1;
        counts[i] = c;
    }
}

#define N 256
#define W 8
void moving_max(int input[N], int output[N-W+1]) {
    #pragma HLS PIPELINE OFF
    for (int i = 0; i <= N-W; i++) {
        #pragma HLS UNROLL factor=1
        int mx = input[i];
        for (int j = 1; j < W; j++)
            if (input[i+j] > mx) mx = input[i+j];
        output[i] = mx;
    }
}

#define N 32
void bitonic_merge(int arr[N], int ascending) {
    #pragma HLS PIPELINE OFF
    for (int step = N/2; step > 0; step >>= 1) {
        for (int i = 0; i < N; i++) {
            #pragma HLS UNROLL factor=1
            int j = i ^ step;
            if (j > i) {
                if ((ascending && arr[i] > arr[j]) || (!ascending && arr[i] < arr[j])) {
                    int tmp = arr[i]; arr[i] = arr[j]; arr[j] = tmp;
                }
            }
        }
    }
}

#define N 128
#define K 16
void xcorr(int sig[N], int kernel[K], int out[N]) {
    #pragma HLS PIPELINE OFF
    for (int i = 0; i < N; i++) {
        #pragma HLS PIPELINE OFF
        int sum = 0;
        for (int j = 0; j < K; j++) {
            #pragma HLS UNROLL factor=1
            int idx = i + j;
            if (idx < N) sum += sig[idx] * kernel[j];
        }
        out[i] = sum;
    }
}

#define N 512
void ewma(int input[N], int output[N], int alpha) {
    #pragma HLS PIPELINE OFF
    output[0] = input[0];
    for (int i = 1; i < N; i++) {
        #pragma HLS PIPELINE OFF
        output[i] = (alpha * input[i] + (256 - alpha) * output[i-1]) >> 8;
    }
}

#define N 64
void prefix_max(int in[N], int out[N]) {
    #pragma HLS PIPELINE OFF
    out[0] = in[0];
    for (int i = 1; i < N; i++) {
        #pragma HLS PIPELINE OFF
        out[i] = (in[i] > out[i-1]) ? in[i] : out[i-1];
    }
}
